pub fn status<T>(self, status: T) -> Builder
    where
        T: TryInto<StatusCode>,
        <T as TryInto<StatusCode>>::Error: Into<crate::Error>,
    {
        self.and_then(move |mut head| {
            head.status = status.try_into().map_err(Into::into)?;
            Ok(head)
        })
    }

pub fn max_buf_size(&mut self, max: usize) -> &mut Self {
    assert!(
        max >= proto::h1::MINIMUM_MAX_BUFFER_SIZE,
        "the max_buf_size cannot be smaller than the minimum that h1 specifies."
    );

    self.h1_max_buf_size = Some(max);
    self.h1_read_buf_exact_size = None;
    self
}

fn next(&mut self) -> Option<Self::Item> {
    match self.kind {
        ParamsIterKind::Small(ref mut iter) => {
            iter.next().map(|p| (p.key_str(), p.value_str()))
        }
        ParamsIterKind::Large(ref mut iter) => {
            iter.next().map(|p| (p.key_str(), p.value_str()))
        }
    }
}

fn env_w_default(
    key: &str,
    default: &str,
) -> Result<String, LeptosConfigError> {
    match std::env::var(key) {
        Ok(val) => Ok(val),
        Err(VarError::NotPresent) => Ok(default.to_string()),
        Err(e) => Err(LeptosConfigError::EnvVarError(format!("{key}: {e}"))),
    }
}

