fn rebuild(self, state: &mut Self::State) {
    let InertElementState(prev, el) = state;
    if &self.html != prev {
        let mut new_el = Rndr::create_element_from_html(self.html.clone());
        el.insert_before_this(&mut new_el);
        el.unmount();
        *el = new_el;
        *prev = self.html;
    }
}

