fn belongs_to_active_model<AM>(mut self, model: &AM) -> Self
    where
        AM: ActiveModelTrait,
    {
        for key in <AM::Entity as EntityTrait>::PrimaryKey::iter() {
            let col = key.into_column();
            self = self.filter(col.eq(model.get(col).unwrap()));
        }
        self
    }

