pub(super) fn transition_to_terminal(&self, count: usize) -> bool {
    let prev = Snapshot(self.val.fetch_sub(count * REF_ONE, AcqRel));
    assert!(
        prev.ref_count() >= count,
        "current: {}, sub: {}",
        prev.ref_count(),
        count
    );
    prev.ref_count() == count
}

pub(super) fn deregexify(&mut self) {
    for field in &mut self.fields {
        field.value = match field.value.take() {
            Some(field::ValueMatch::Pat(pat)) => {
                Some(field::ValueMatch::Debug(pat.into_debug_match()))
            }
            x => x,
        }
    }
}

fn fires_on_drop() {
    let fired = Arc::new(AtomicBool::new(false));
    let fired_for_guard = fired.clone();
    {
        let _guard = OnEarlyDropGuard::new(move || {
            fired_for_guard.store(true, Ordering::Relaxed);
        });
    }
    assert!(fired.load(Ordering::Relaxed));
}
